module piso_shift_register(
	input clk,
	input reset_n,
	input load,
	input [7:0] data_in,
	output reg data_out);

reg [7:0] data_buffer;

always @(posedge clk)
	if (!reset_n)
		data_buffer <= 0;
	else if (load)
		data_buffer <= data_in;
	else
		data_buffer <= {data_buffer[6:0], 1'b0};

always @(data_buffer)
	data_out = data_buffer[7];

endmodule
